import{_ as n}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as a,c as r,a as e,b as o,d as c,e as i,r as l}from"./app.e1f6d69b.js";const s={},h=i('<div class="custom-container tip"><p class="custom-container-title">人生啊</p><p>泡夜店、纹身、买醉，这些事情看起来很酷，但其实一点难度都没有，只要你想办到随时都可以。</p><p>真正酷的，应该是那些不容易办到的，比如：读书、赚钱、健身、早睡早起、孝顺父母，用炙热的心爱人爱己，用你毕生的精力去战胜一个个专业领域。</p><p><mark>低级的欲望放纵即可获得，高级的欲望只有克制才能达成</mark></p></div><hr><h2 id="关于我" tabindex="-1"><a class="header-anchor" href="#关于我" aria-hidden="true">#</a> 关于我</h2><p>鄙姓杨，yuanyxh 中的 yxh 就是我的姓名，目前是一名前端开发工程师，爱好编程、知识原理、科学、逆向工程、历史(三国)，喜欢看书、动漫、电影。</p><p>本人一开始是从没想过从事 it 开发的，甚至于不知道编程是什么，接触到前端还是因为疫情在家躺了一段时间，接触到了 Android 刷机（系统修改），由此得知了编译、反编译等知识，开始对逆向感兴趣，由浅入深一步一步开始自学，后来想找一份与编程相关的工作，因为前端入门简单所以成为了一名前端开发。</p><p>我的学习方式偏向于书籍，然后是官方文档、博客文章、视频等；很多人跟我说过，阅读官方文档是最好的学习方式，但我的理解不同，官方文档固然权威，但大部分只会告诉你如何使用、Api、最佳实践等，而好的书籍，包含作者对语言、框架的理解，多年使用的经验，源码、原理的解读，让你能够知其然而知其所以然，这也是我从逆向中学到的：<strong><em>溯其根源，达其本质</em></strong>。</p><p>记得在刚学前端的时候，我在网上看到了一篇不错的 JQuery 文章，发到了学习交流群，一位老师看到说了一句：</p><blockquote><p>JQuery 已经不学了，JQuery 已经过时了。</p></blockquote><p>我的回答大概是：</p><blockquote><p>学一下他的设计思想，这个不会过时吧</p></blockquote><p>现在我依旧如此认为</p><h2 id="关于博客" tabindex="-1"><a class="header-anchor" href="#关于博客" aria-hidden="true">#</a> 关于博客</h2>',12),p={href:"https://yang-xianzhu.github.io/blog/home/",target:"_blank",rel:"noopener noreferrer"},d=e("p",null,"博客不定时发布文章，内容不固定，目前会产出较多前端相关文章，对语言没有鄙视链，喜欢一切有其原理的东西，也喜欢知识进脑子里的感觉☺️。",-1),u=e("h2",{id:"联系我",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#联系我","aria-hidden":"true"},"#"),o(" 联系我")],-1),_=e("p",null,"若本站文章中引用的素材侵犯了您的权益，或对部分内容有更好的建议，欢迎联系：",-1),m=e("ul",null,[e("li",null,"QQ：725441272"),e("li",null,"微信：hxy3130gbs"),e("li",null,[o("Email："),e("a",{href:"mailto:yang_xuheng@163.com"},"yang_xuheng@163.com")])],-1);function x(f,b){const t=l("ExternalLinkIcon");return a(),r("div",null,[h,e("p",null,[o("为什么搭建这个博客呢，起因是一位朋友给我看了他的 "),e("a",p,[o("博客"),c(t)]),o("，心血来潮，另一方面也确实需要对以往所学知识进行沉淀，以及对未来知识的记录。")]),d,u,_,m])}const y=n(s,[["render",x],["__file","intro.html.vue"]]);export{y as default};
